SELECT a.*, c.title as competition_title, u.real_name as student_name, t.name as team_name
FROM award a
LEFT JOIN competition c ON a.competition_id = c.id
LEFT JOIN user u ON a.student_id = u.id
LEFT JOIN team t ON a.team_id = t.id

    
        AND a.competition_id = #{competitionId}
    
    
        AND a.student_id = #{studentId}
    
    
        AND a.award_level = #{awardLevel}
    

ORDER BY a.ranking ASC

mapper.update:
UPDATE award
award_level = #{awardLevel}, award_name = #{awardName}, score = #{score}, ranking = #{ranking},
WHERE id = #{id}
